import { Component, OnInit } from '@angular/core';
import { FormGroup, FormBuilder, ReactiveFormsModule, FormControl } from '@angular/forms';
import { Router, RouterLink } from '@angular/router';
import { UserService } from '../../services/users.service';
import { UserResponse } from '../../models/userResponse';
import { v4 as uuidv4 } from 'uuid';

@Component({
  selector: 'app-signup',
  imports: [ReactiveFormsModule, RouterLink],
  templateUrl: './signup.html',
  styleUrls: ['./signup.css'],
  standalone: true
})
export class Signup implements OnInit {

  signupForm: FormGroup;
  public token: string = "";
  public isLogin: boolean = false;
  public showSpinner: boolean = false;

  constructor(
    private readonly formBuilder: FormBuilder,
    private readonly router: Router,
    private readonly userService: UserService
  ) {

    this.signupForm = this.formBuilder.group({
      email: new FormControl(''),
      password: new FormControl('')
    });
  }

  ngOnInit(): void {
    console.log("url..." + this.router.url);

    if (this.router.url.endsWith("login")) {
      this.isLogin = true;
    }
  }

  submit() {

    this.showSpinner = true;

    const thisUser = {
      id: uuidv4(),
      email: this.signupForm.get('email')?.value,
      password: this.signupForm.get('password')?.value
    };

    const jsonString: string = JSON.stringify(thisUser);
    console.log('to signup...name:' + jsonString);

    /*
    if (this.isLogin) {
      this.userService.signin(thisUser).subscribe((data) => {
        this.postSubmit(data);
      });
    }
    else
    { 
      this.userService.signup(thisUser).subscribe((data) => {
        this.postSubmit(data);
      });
    }
    */
  }

  postSubmit(userResponse: UserResponse) {
    if (userResponse) {
      this.token = userResponse.token;
      console.log("Successfully logged in...token:" + userResponse.token);      

      this.router.navigate(['/invoice-list']);
    } else {
      console.log("Something went wrong...");
    }
  }


}
<div class="row">
  <div class="col-md-3"></div>

  <div class="card shadow-sm col-md-6 p-0">
    <div class="card-header bg-lightly py-3">
      <h3 class="card-title">
        {{ isLogin ? "Login" : "Register User" }}
      </h3>
    </div>

    <div class="card-body p-4">
      <form [formGroup]="signupForm" (ngSubmit)="submit()" class="py-2">

        <div class="form-group">
          <label for="email">Email</label>
          <input type="email" class="form-control" formControlName="email" placeholder="user@company.co.za">
        </div>

        <div class="form-group">
          <label for="password">Password</label>
          <input type="password" class="form-control" formControlName="password" placeholder="Us3r0n3">
        </div>

        <div class="row form-group py-4">
          <button type="submit"
                  class="btn btn-primary col-md-3"
                  [disabled]="!signupForm.valid">
            Submit
          </button>

          <div class="spinner-border col-md-3 mx-4"
               *ngIf="showSpinner"
               role="status">
            <span class="visually-hidden">Loading...</span>
          </div>

          <a class="nav-link px-2 link-secondary col-md-3 "
             *ngIf="!showSpinner"
             [routerLink]="['/customer-list']">
            Cancel
          </a>


        </div>
      </form>
    </div>
  </div>

  <div class="col-md-3"></div>
</div>
